#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <fcntl.h>
#include <errno.h>

#define MG_DIR ".minigit"
#define MG_INDEX MG_DIR "/index"
#define MG_COMMITS MG_DIR "/commits"
#define MG_REFS MG_DIR "/refs"
#define MG_REFS_HEAD MG_REFS "/HEAD"

void fatal(const char *msg) {
    perror(msg);
    exit(EXIT_FAILURE);
}

void ensure_dir(const char *path) {
    struct stat st;
    if (stat(path, &st) == -1) {
        if (mkdir(path, 0755) == -1) fatal("mkdir");
    }
}

void write_file(const char *path, const char *content) {
    int fd = open(path, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) fatal("open write");
    if (write(fd, content, strlen(content)) == -1) fatal("write");
    close(fd);
}

char *read_file(const char *path, size_t *len) {
    int fd = open(path, O_RDONLY);
    if (fd == -1) fatal("open read");
    off_t size = lseek(fd, 0, SEEK_END);
    lseek(fd, 0, SEEK_SET);
    char *buf = malloc(size + 1);
    if (read(fd, buf, size) != size) fatal("read");
    buf[size] = 0;
    close(fd);
    if (len) *len = size;
    return buf;
}

void copy_file(const char *src, const char *dst) {
    size_t len;
    char *buf = read_file(src, &len);
    int fd = open(dst, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) fatal("copy open");
    if (write(fd, buf, len) == -1) fatal("copy write");
    close(fd);
    free(buf);
}

void minigit_init(void) {
    ensure_dir(MG_DIR);
    ensure_dir(MG_COMMITS);
    ensure_dir(MG_REFS);
    write_file(MG_REFS_HEAD, "master");
}

char *sha1(const char *content) {
    static char hash[9];
    unsigned long h = 5381;
    int c;
    while ((c = *content++))
        h = ((h << 5) + h) + c;
    snprintf(hash, sizeof(hash), "%08lx", h);
    return hash;
}

void minigit_add(const char *path) {
    FILE *index = fopen(MG_INDEX, "a");
    if (!index) fatal("fopen index");
    fprintf(index, "%s %s\n", path, sha1(path));
    fclose(index);
}

char *current_branch(void) {
    return read_file(MG_REFS_HEAD, NULL);
}

char *current_commit(void) {
    char *branch = current_branch();
    char path[256];
    snprintf(path, sizeof(path), "%s/%s", MG_REFS, branch);
    free(branch);
    if (access(path, F_OK) == -1) return NULL;
    return read_file(path, NULL);
}

void commit_hash(const char *parent, char *out) {
    char buf[256];
    time_t now = time(NULL);
    snprintf(buf, sizeof(buf), "%s %ld", parent ? parent : "", now);
    strcpy(out, sha1(buf));
}

void minigit_commit(const char *msg) {
    char *parent = current_commit();
    char hash[9];
    commit_hash(parent, hash);
    char dir[256];
    snprintf(dir, sizeof(dir), "%s/%s", MG_COMMITS, hash);
    ensure_dir(dir);
    char meta[256];
    snprintf(meta, sizeof(meta), "%s/%s", dir, "meta");
    FILE *m = fopen(meta, "w");
    if (!m) fatal("fopen meta");
    fprintf(m, "parent %s\n", parent ? parent : "none");
    fprintf(m, "message %s\n", msg);
    fclose(m);
    FILE *idx = fopen(MG_INDEX, "r");
    if (!idx) fatal("fopen index");
    char path[256], blob[256];
    while (fscanf(idx, "%s %s", path, blob) == 2) {
        char dst[256];
        snprintf(dst, sizeof(dst), "%s/%s", dir, blob);
        copy_file(path, dst);
    }
    fclose(idx);
    char ref[256];
    char *branch = current_branch();
    snprintf(ref, sizeof(ref), "%s/%s", MG_REFS, branch);
    write_file(ref, hash);
    free(branch);
    free(parent);
}

void minigit_checkout(const char *hash) {
    char dir[256];
    if (strcmp(hash, "master") == 0) {
        char *master = current_commit();
        if (!master) fatal("no commits");
        snprintf(dir, sizeof(dir), "%s/%s", MG_COMMITS, master);
        free(master);
    } else {
        snprintf(dir, sizeof(dir), "%s/%s", MG_COMMITS, hash);
    }
    DIR *d = opendir(dir);
    if (!d) fatal("opendir commit");
    struct dirent *ent;
    while ((ent = readdir(d))) {
        if (ent->d_name[0] == '.') continue;
        char src[256], dst[256];
        snprintf(src, sizeof(src), "%s/%s", dir, ent->d_name);
        snprintf(dst, sizeof(dst), "%s", ent->d_name);
        copy_file(src, dst);
    }
    closedir(d);
    if (strcmp(hash, "master") != 0) {
        write_file(MG_REFS_HEAD, hash);
    } else {
        write_file(MG_REFS_HEAD, "master");
    }
}

void minigit_reset(const char *hash) {
    minigit_checkout(hash);
    char ref[256];
    char *branch = current_branch();
    snprintf(ref, sizeof(ref), "%s/%s", MG_REFS, branch);
    write_file(ref, hash);
    free(branch);
}
